import{c as n,Q as t,j as i,m as s}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Skill Issue: Harness Engineering for Coding Agents","description":"","frontmatter":{"title":"Skill Issue: Harness Engineering for Coding Agents","authors":"Kyle (HumanLayer)","published":"2026-03-12T00:00:00.000Z","source":"https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents"},"headers":[],"relativePath":"research/agent-harness/references/2026-03-12-skill-issue-harness-engineering.md","filePath":"research/agent-harness/references/2026-03-12-skill-issue-harness-engineering.md","lastUpdated":1779894392000}'),o={name:"research/agent-harness/references/2026-03-12-skill-issue-harness-engineering.md"};function a(r,e,l,c,d,u){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="skill-issue-harness-engineering-for-coding-agents" tabindex="-1">Skill Issue: Harness Engineering for Coding Agents <a class="header-anchor" href="#skill-issue-harness-engineering-for-coding-agents" aria-label="Permalink to &quot;Skill Issue: Harness Engineering for Coding Agents&quot;">​</a></h1><p><strong>Author</strong>: Kyle (HumanLayer)<br><strong>Published</strong>: 2026-03-12<br><strong>Read time</strong>: ~23 min<br><strong>Source</strong>: <a href="https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents" target="_blank" rel="noreferrer">https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents</a><br><strong>Tags</strong>: #agents #claudecode #best-practices</p><hr><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The article opens by documenting widespread failures in coding agents over the past year: ignoring instructions, executing dangerous commands unprompted, and failing on simple tasks. Rather than waiting for better models (&quot;GPT-6 will fix it&quot;), the author argues the real issue is <strong>configuration</strong>, not model capability.</p><p>The key insight: &quot;it&#39;s not a model problem. It&#39;s a configuration problem.&quot; Even as models improve, they&#39;ll continue failing in unexpected ways because non-deterministic systems inherently produce unpredictable failure modes.</p><hr><h2 id="core-definition-the-coding-agent-harness" tabindex="-1">Core Definition: The Coding Agent Harness <a class="header-anchor" href="#core-definition-the-coding-agent-harness" aria-label="Permalink to &quot;Core Definition: The Coding Agent Harness&quot;">​</a></h2><p>The foundational equation presented:</p><blockquote><p>coding agent = AI model(s) + harness</p></blockquote><p>The &quot;harness&quot; encompasses configuration points like skills, MCP servers, sub-agents, memory systems, and instruction files (CLAUDE.md/AGENTS.md). These represent the agent&#39;s runtime and environmental interfaces.</p><hr><h2 id="harness-engineering-explained" tabindex="-1">Harness Engineering Explained <a class="header-anchor" href="#harness-engineering-explained" aria-label="Permalink to &quot;Harness Engineering Explained&quot;">​</a></h2><p><strong>Harness engineering</strong> (coined by Viv Trivedy) means systematically improving agent performance by engineering solutions whenever agents make mistakes. Mitchell Hashimoto&#39;s definition captures this: whenever an agent fails, spend time ensuring it never fails that way again.</p><p>The article positions harness engineering as a subset of <strong>context engineering</strong> (a Dex Horthy concept from &quot;12-factor agents&quot;), which itself encompasses prompt engineering and systematic reliability improvements.</p><p>Harness engineering specifically addresses:</p><ul><li>Granting new capabilities</li><li>Teaching codebase knowledge beyond training data</li><li>Adding determinism beyond system prompt instructions</li><li>Adapting behavior for specific codebases</li><li>Improving success rates beyond &quot;magic prompts&quot;</li><li>Managing context window inflation</li></ul><hr><h2 id="implementation-key-configuration-points" tabindex="-1">Implementation: Key Configuration Points <a class="header-anchor" href="#implementation-key-configuration-points" aria-label="Permalink to &quot;Implementation: Key Configuration Points&quot;">​</a></h2><h3 id="claude-md-agents-md-files" tabindex="-1">CLAUDE.md &amp; AGENTS.md Files <a class="header-anchor" href="#claude-md-agents-md-files" aria-label="Permalink to &quot;CLAUDE.md &amp; AGENTS.md Files&quot;">​</a></h3><p>These markdown files at repository root inject deterministically into the agent&#39;s system prompt. Key principles from prior HumanLayer guidance:</p><ul><li>Avoid auto-generation; craft carefully</li><li>&quot;Less is more&quot; regarding instructions</li><li>Use progressive disclosure</li><li>Keep content concise and universally applicable</li><li>HumanLayer&#39;s own CLAUDE.md runs under 60 lines</li></ul><p><strong>The ETH Zurich Study Context</strong>: A 2025 study tested 138 agentfiles and found:</p><ul><li>LLM-generated files hurt performance while costing 20%+ more tokens</li><li>Human-written ones helped approximately 4%</li><li>Agents spent 14-22% more reasoning tokens processing context instructions without improving resolution rates</li></ul><p>However, the article argues careful reading shows the study validates their recommendations: avoid auto-generation, minimize instruction bloat, use progressive disclosure, keep universally applicable content.</p><h3 id="mcp-servers-for-tools" tabindex="-1">MCP Servers for Tools <a class="header-anchor" href="#mcp-servers-for-tools" aria-label="Permalink to &quot;MCP Servers for Tools&quot;">​</a></h3><p>MCP servers extend agent capabilities beyond file I/O and bash commands. While the specification includes resources, prompts, and elicitations, these features lack robust harness support. MCP servers can run locally or via HTTP, connecting agents to services like Linear and Sentry.</p><p><strong>Critical Warning</strong>: Tool descriptions from MCP servers inject into system prompts, creating prompt injection vectors. Never connect untrusted servers.</p><p><strong>Problem: Too Many Tools</strong></p><ul><li>Context window fills with tool descriptions</li><li>Agents enter &quot;the dumb zone&quot; faster</li><li>Each irrelevant tool description consumes instruction budget</li></ul><p>Solution: Anthropic released experimental MCP tool search to progressively disclose tools when excessive numbers are connected.</p><p><strong>Alternative Strategy</strong>: If an MCP server duplicates CLI functionality already in training data (GitHub, Docker, databases), prompt agents to use the CLI instead for better composability and context efficiency.</p><p><strong>HumanLayer Example</strong>: They replaced the Linear MCP server with a custom CLI wrapper providing context-efficient responses, adding six example usages in CLAUDE.md. This saved thousands of tokens from MCP tool definitions.</p><h3 id="skills-for-reusable-knowledge" tabindex="-1">Skills for Reusable Knowledge <a class="header-anchor" href="#skills-for-reusable-knowledge" aria-label="Permalink to &quot;Skills for Reusable Knowledge&quot;">​</a></h3><p>Skills provide <strong>progressive disclosure</strong>—agents access specific instructions, knowledge, or tools only when needed. When activated, SKILL.md files load as user messages, and agents learn the skill directory location.</p><p>Skills can bundle multiple markdown files with creative progressive disclosure: main SKILL.md can reference additional files agents should read conditionally.</p><p><strong>Limitation</strong>: Cannot directly bundle MCP servers or custom agent tools. Instead, distribute as executables, CLIs, NPM packages, or instruct agents to install via the SKILL.md file.</p><p><strong>Warning</strong>: Skill registries have distributed malicious skills. Treat like untrusted npm packages—review before installation.</p><h3 id="sub-agents-for-context-control" tabindex="-1">Sub-Agents for Context Control <a class="header-anchor" href="#sub-agents-for-context-control" aria-label="Permalink to &quot;Sub-Agents for Context Control&quot;">​</a></h3><p>Sub-agents enable <strong>context encapsulation</strong>: dispatching agents see only the sub-agent prompt and final result, not intermediate tool calls, tool results, or messages. This maintains coherency across longer sessions.</p><p><strong>Key Benefit</strong>: Sub-agents function as &quot;context firewalls&quot; preventing intermediate noise accumulation in parent threads.</p><p><strong>Context Rot Research</strong>: Chroma&#39;s research confirms models perform worse at longer context lengths. Performance degradation steepens when low semantic similarity exists between questions and contextual information—distractors compound at longer context windows.</p><p><strong>Cost Control</strong>: Use expensive models (Opus) for parent sessions handling planning/orchestration, cheaper models (Sonnet/Haiku) for discrete sub-agent tasks.</p><p><strong>Use Cases</strong>:</p><ul><li>Locating specific definitions/implementations</li><li>Analyzing codebase patterns</li><li>Tracing information flow across service boundaries</li><li>Code/documentation/web research tasks</li></ul><p>Sub-agents should return highly condensed responses with source citations (filepath:line format) for progressive disclosure.</p><p><strong>Implementation Without Native Support</strong>: Write MCP servers providing tools for launching new agent sessions, receiving parent prompts, launching sub-agents with those prompts, and returning final responses.</p><h3 id="hooks-for-control-flow" tabindex="-1">Hooks for Control Flow <a class="header-anchor" href="#hooks-for-control-flow" aria-label="Permalink to &quot;Hooks for Control Flow&quot;">​</a></h3><p>Hooks (in Claude Code/Opencode, similar to git hooks) execute automatically at lifecycle events and various agent moments. They can:</p><ul><li>Run silently when events occur</li><li>Run on tool calls and return additional context</li><li>Surface build/type errors forcing resolution before agent completion</li></ul><p><strong>Use Cases</strong>:</p><ul><li>Notifications (sounds when finished/needs attention)</li><li>Approvals/denials of tool calls based on rules</li><li>Integrations (Slack messages, GitHub PRs, preview environments)</li><li>Verification (typecheck/build on agent stop)</li></ul><p><strong>Example Hook</strong>: The article includes a bash script that runs on agent stop to execute biome formatting and TypeScript typechecks. Success is silent; only errors surface to trigger agent re-engagement.</p><hr><h2 id="back-pressure-mechanisms" tabindex="-1">Back-Pressure Mechanisms <a class="header-anchor" href="#back-pressure-mechanisms" aria-label="Permalink to &quot;Back-Pressure Mechanisms&quot;">​</a></h2><p>Success likelihood correlates strongly with agent ability to verify its own work. Effective back-pressure mechanisms include:</p><ul><li>Typechecks and builds (in strongly-typed languages)</li><li>Unit/integration tests</li><li>Code coverage reporting</li><li>UI interaction testing (Playwright, agent-browser)</li></ul><p><strong>Critical Principle</strong>: Verification must be context-efficient. Success should be silent; only failures produce verbose output.</p><p>HumanLayer learned this by initially running full test suites (4,000+ lines of passing tests), which flooded context windows causing agents to lose task focus. Now they surface only errors.</p><hr><h2 id="strategic-insights" tabindex="-1">Strategic Insights <a class="header-anchor" href="#strategic-insights" aria-label="Permalink to &quot;Strategic Insights&quot;">​</a></h2><h3 id="long-context-models-a-skeptical-take" tabindex="-1">Long-Context Models: A Skeptical Take <a class="header-anchor" href="#long-context-models-a-skeptical-take" aria-label="Permalink to &quot;Long-Context Models: A Skeptical Take&quot;">​</a></h3><p>Extended-context models don&#39;t necessarily solve problems better—they just make the haystack bigger. In needle-in-a-haystack tasks, bigger context windows don&#39;t improve finding ability; they deepen the &quot;dumb zone&quot; by allowing more instructions to accumulate.</p><p>The solution isn&#39;t longer context but better context isolation via sub-agents providing fresh, small, high-relevance windows.</p><h3 id="working-backwards-from-model-limitations" tabindex="-1">Working Backwards From Model Limitations <a class="header-anchor" href="#working-backwards-from-model-limitations" aria-label="Permalink to &quot;Working Backwards From Model Limitations&quot;">​</a></h3><p>Viv&#39;s framework derives harness components by understanding what models can&#39;t do natively: system prompts provide instructions, tools/MCPs extend capabilities, context manages scope, sub-agents enable distributed work.</p><h3 id="post-training-coupling" tabindex="-1">Post-Training Coupling <a class="header-anchor" href="#post-training-coupling" aria-label="Permalink to &quot;Post-Training Coupling&quot;">​</a></h3><p>Frontier models are post-trained on specific harnesses (Claude with Claude Code, GPT-5 Codex with Codex harness). While models may perform better with their training harness, they can be over-fitted to it.</p><p>Terminal Bench 2.0 data shows Opus 4.6 ranked #33 in Claude Code but jumped to #5 when placed in different harnesses—demonstrating harness configuration matters enormously.</p><hr><h2 id="practical-recommendations" tabindex="-1">Practical Recommendations <a class="header-anchor" href="#practical-recommendations" aria-label="Permalink to &quot;Practical Recommendations&quot;">​</a></h2><h3 id="what-worked" tabindex="-1">What Worked <a class="header-anchor" href="#what-worked" aria-label="Permalink to &quot;What Worked&quot;">​</a></h3><ul><li>Starting simple, adding configuration only after actual failures</li><li>Designing, testing, iterating, and discarding unhelpful changes</li><li>Distributing battle-tested configurations team-wide</li><li>Optimizing for iteration speed over one-shot success</li><li>Carefully paring down exposed capabilities after understanding actual needs</li></ul><h3 id="what-didn-t-work" tabindex="-1">What Didn&#39;t Work <a class="header-anchor" href="#what-didn-t-work" aria-label="Permalink to &quot;What Didn&#39;t Work&quot;">​</a></h3><ul><li>Designing ideal harness upfront before real failures</li><li>Installing dozens of skills/MCP servers preemptively</li><li>Running full test suites at every session end (use subsets instead)</li><li>Micro-optimizing sub-agent tool access (causes tool thrash)</li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>The article concludes that most coding agent performance issues stem from harness configuration, not model capability. Configuration points—agentfiles, MCP servers, skills, sub-agents, hooks, and back-pressure mechanisms—contain most leverage for improvement.</p><p><strong>Final insight</strong>: &quot;The model is probably fine. It&#39;s just a skill issue.&quot;</p><p>The approach emphasizes bias toward shipping: optimize harness configuration only when it enables faster, higher-quality code delivery. When failures occur, engineer specific solutions to prevent recurrence rather than pursuing preemptive optimizations.</p><hr><h2 id="related-content-links" tabindex="-1">Related Content Links <a class="header-anchor" href="#related-content-links" aria-label="Permalink to &quot;Related Content Links&quot;">​</a></h2><ul><li>Previous: &quot;Getting Claude to Actually Read Your CLAUDE.md&quot; (March 17, 2026)</li><li>Older: &quot;A Brief History of Ralph&quot; (January 6, 2026)</li></ul>',83)])])}const p=n(o,[["render",a]]);export{h as __pageData,p as default};
